('itch-io-publishing-workflow', 'platform-and-business-awareness', 'topic', NULL, NULL, NULL, 'itch.io Publishing Workflow', 'Learn and practice itch.io Publishing Workflow.', 224, 'choice', 1, 'beginner', '{"source": "roadmap.sh/game-developer", "parentGroup": "platform-and-business-awareness"}'::jsonb, true, true, '["Explain itch.io Publishing Workflow in practical game development terms.", "Apply itch.io Publishing Workflow in a playable prototype or production-style workflow."]'::jsonb, '["Create notes, code, or a test scene demonstrating itch.io Publishing Workflow.", "Be able to debug common mistakes and explain tradeoffs."]'::jsonb),
